import React, { useState,useEffect } from "react";
import { Link } from "react-router-dom";
import { useLocation } from "react-router";
import Axios from "axios";

export const CartBlock = (props) => {
  const { cart } = props;
  const [Products, setProducts] = useState([]);
  useEffect(() => {
    getProducts();
}, [])

const url = "http://localhost:5000/api/product/getProducts"
const getProducts = (variables) => {
    Axios.post(url, variables)
        .then(response => {
            if (response.data.success) {
                setProducts(response.data.products)
                console.log(response.data.products)
            }
            else {
                alert("failed to fetch product data")
            }
        })

}
  let location = useLocation();
  return (
    <>
      {location.pathname === "/category" ? (
        <div></div>
      ) : (
        <tbody>
          {Products.filter((product) => product._id === cart.id).map(
            (product) => (
              <tr>
                <td className="product-thumbnail">
                  <Link to="/">
                    <img
                      src={product.image[0]}
                      alt=""
                      style={{ height: "91px", width: "82px" }}
                    />
                  </Link>
                </td>
                <td className="product-name">
                  <h4>
                    <Link to="/">{product.title}</Link>
                  </h4>
                </td>
                <td className="product-price">₹{product.price}</td>
                <td className="product-quantity">
                  <div className="cart--plus--minus">
                    <form action="#" className="num-block">
                      <input
                        type="text"
                        className="in-num"
                        value={cart.quantity}
                        readonly=""
                      />
                      <div className="qtybutton-box">
                        <span className="plus">
                          <i className="fas fa-angle-up"></i>
                        </span>
                        <span className="minus dis">
                          <i className="fas fa-angle-down"></i>
                        </span>
                      </div>
                    </form>
                  </div>
                </td>
                <td className="product-subtotal">
                  <span>₹{product.price}</span>
                </td>
                <td className="product-delete">
                  <Link to="/">
                    <i className="far fa-trash-alt"></i>
                  </Link>
                </td>
              </tr>
            )
          )}
        </tbody>
      )}
    </>
  );
};
